import{_ as a,o as e,c as i,a0 as l}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"🗺️ 領地保護與密碼箱安全系統","description":"","frontmatter":{},"headers":[],"relativePath":"Claims-Lockboxes.md","filePath":"Claims-Lockboxes.md"}'),r={name:"Claims-Lockboxes.md"};function t(n,o,s,c,g,d){return e(),i("div",null,[...o[0]||(o[0]=[l('<h1 id="🗺️-領地保護與密碼箱安全系統" tabindex="-1">🗺️ 領地保護與密碼箱安全系統 <a class="header-anchor" href="#🗺️-領地保護與密碼箱安全系統" aria-label="Permalink to &quot;🗺️ 領地保護與密碼箱安全系統&quot;">​</a></h1><p>本章節介紹遊戲內的領地保護系統與箱子安全防盜密碼鎖系統，玩家可透過網頁儀表板管理權限與防護狀態。</p><hr><h2 id="_1-🗺️-領地保護區系統-claims" tabindex="-1">1. 🗺️ 領地保護區系統 (Claims) <a class="header-anchor" href="#_1-🗺️-領地保護區系統-claims" aria-label="Permalink to &quot;1. 🗺️ 領地保護區系統 (Claims)&quot;">​</a></h2><p>玩家可以使用領地保護系統來劃定個人專屬區域，防止其他玩家進行破壞或開啟您的箱子。</p><h3 id="a-框選領地範圍-wooden-hoe-selection" tabindex="-1">A. 框選領地範圍 (Wooden Hoe Selection) <a class="header-anchor" href="#a-框選領地範圍-wooden-hoe-selection" aria-label="Permalink to &quot;A. 框選領地範圍 (Wooden Hoe Selection)&quot;">​</a></h3><ol><li>玩家手持 <strong>木鋤頭 (Wooden Hoe)</strong>。</li><li>對著地面第一個角落方塊按**【左鍵】**設定角落 A。</li><li>對著地面對角線第二個角落方塊按**【右鍵】**設定角落 B。 <ul><li><em>限制</em>：兩個角落方塊必須處於同一個世界。</li><li><em>注意</em>：一旦成功建立領地或退出遊戲，已框選的位置會自動清除。</li></ul></li></ol><h3 id="b-購買與收費標準-purchase-pricing" tabindex="-1">B. 購買與收費標準 (Purchase &amp; Pricing) <a class="header-anchor" href="#b-購買與收費標準-purchase-pricing" aria-label="Permalink to &quot;B. 購買與收費標準 (Purchase &amp; Pricing)&quot;">​</a></h3><ol><li>購買領地：框選完畢後，在聊天欄輸入 <strong><code>/claim</code></strong> 進行購買。</li><li>區塊計費：系統會自動計算框選區域所覆蓋的 <strong>16x16 垂直方塊柱（整個區塊）</strong> 數量。 <ul><li><em>收費標準</em>：<strong>每個區塊收費 $30 遊戲金幣</strong>（垂直保護範圍從世界最低點到最高點）。</li></ul></li><li><strong>安全檢查</strong>：系統確認您帳戶餘額足夠且保護區不與他人領地重疊後，扣除金幣並建立保護區。</li></ol><h3 id="c-網頁領地權限管理-web-claims-manager" tabindex="-1">C. 網頁領地權限管理 (Web Claims Manager) <a class="header-anchor" href="#c-網頁領地權限管理-web-claims-manager" aria-label="Permalink to &quot;C. 網頁領地權限管理 (Web Claims Manager)&quot;">​</a></h3><p>玩家可直接登入網頁儀表板，在「領地管理」分頁中查詢您所擁有的領地，並為其他玩家指派以下四種防護權限：</p><ul><li><strong>Build (建造)</strong>：允許在領地內放置方塊。</li><li><strong>Break (破壞)</strong>：允許在領地內挖掘或破壞方塊。</li><li><strong>Containers (容器)</strong>：允許開啟領地內的箱子、熔爐等容器。</li><li><strong>Interact (互動)</strong>：允許使用領地內的按鈕、拉桿、門與門板。</li></ul><hr><h2 id="_2-🔒-箱子密碼鎖系統-lockbox-security" tabindex="-1">2. 🔒 箱子密碼鎖系統 (Lockbox Security) <a class="header-anchor" href="#_2-🔒-箱子密碼鎖系統-lockbox-security" aria-label="Permalink to &quot;2. 🔒 箱子密碼鎖系統 (Lockbox Security)&quot;">​</a></h2><p>獨立於領地之外的安全防護，適合在公共區域或與朋友共享的基地中鎖定特定的重要物資箱。</p><h3 id="a-上鎖操作-locking-box" tabindex="-1">A. 上鎖操作 (Locking Box) <a class="header-anchor" href="#a-上鎖操作-locking-box" aria-label="Permalink to &quot;A. 上鎖操作 (Locking Box)&quot;">​</a></h3><ol><li>面對一個箱子（最大距離 4.5 格內）。</li><li>在聊天欄輸入 <strong><code>/padlock</code></strong> 啟動鎖定模式。</li><li>聊天欄會提示您輸入密碼。</li><li><strong>輸入密碼</strong>：您發送的下一條聊天訊息將會自動設定為密碼，該訊息不會發送到公開頻道上，其他玩家不會看見。</li><li>上鎖成功後，系統會播放鎖定音效。其他玩家將完全無法打開或破壞此箱子。</li></ol><h3 id="b-授權與解除授權-access-permissions" tabindex="-1">B. 授權與解除授權 (Access Permissions) <a class="header-anchor" href="#b-授權與解除授權-access-permissions" aria-label="Permalink to &quot;B. 授權與解除授權 (Access Permissions)&quot;">​</a></h3><ul><li><strong>遊戲內指令授權</strong>：面對已經上鎖的箱子，在遊戲內輸入：<strong><code>/padlock grant &lt;玩家名稱&gt;</code></strong>。</li><li><strong>遊戲內解除授權</strong>：面對已經上鎖的箱子，在遊戲內輸入：<strong><code>/padlock revoke &lt;玩家名稱&gt;</code></strong>。</li><li>該玩家即會被加入/移除此密碼箱的授權名單，授權名冊會即時同步至網頁儀表板。</li></ul><h3 id="c-網頁密碼鎖遙控管理-web-lockbox-management" tabindex="-1">C. 網頁密碼鎖遙控管理 (Web Lockbox Management) <a class="header-anchor" href="#c-網頁密碼鎖遙控管理-web-lockbox-management" aria-label="Permalink to &quot;C. 網頁密碼鎖遙控管理 (Web Lockbox Management)&quot;">​</a></h3><p>玩家可透過網頁儀表板的「密碼安全鎖」分頁，即時查看您擁有的安全密碼箱並進行以下遠端操控：</p><ul><li><strong>查閱座標</strong>：列出所有安全箱的確切座標 (X, Y, Z) 與擁有權。</li><li><strong>遠端授權玩家</strong>：直接在輸入框中鍵入玩家名稱，並點選「新增授權」。</li><li><strong>遠端撤銷玩家</strong>：點選已授權標籤旁邊的「×」按鈕即可即時撤銷該玩家的開啟權限。</li><li><strong>遠端修改密碼</strong>：點選「修改密碼」按鈕，彈出輸入框輸入新密碼，即可直接重設該安全箱的開啟密碼。</li><li><strong>遠端註銷密碼鎖</strong>：點選紅色的「註銷密碼鎖」按鈕，即可將鎖頭拆除，完全解除該箱子的安全防護。</li><li><strong>離線防鎖死修改</strong>：當 Minecraft 遊戲伺服器離線時，系統支援離線更新機制，直接讀寫修改伺服器設定檔以保存設定，待伺服器重啟時自動套用。</li></ul>',22)])])}const b=a(r,[["render",t]]);export{m as __pageData,b as default};
